#include <bits/stdc++.h>
using namespace std;
const int N=1005;
int st[15][N],n,q;
int fun(int l,int r)
{
	int len=r-l+1;
	int len2=log2(len);
	return __gcd(st[len2][l],st[len2][r-(1<<len2)+1]);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>q;
	for(int i=1;i<=n;i++)
	{
		cin>>st[0][i];
	}
	for(int i=1;i<=log2(n);i++)
	{
		for(int j=1;j<=n;j++)
		{
			st[i][j]=__gcd(st[i-1][j],st[i-1][j+(1<<(i-1))]);
		}
	}
	for(int i=1;i<=q;i++)
	{
		int x,y;
		cin>>x>>y;
		cout<<fun(x,y)<<'\n';
	}
	return 0;
}
